'use client';

import { useState, useEffect } from 'react';
import Link from 'next/link';
import { Menu, X } from 'lucide-react';

/*
  SENTIRA — Logo-matched Colour System
  ──────────────────────────────────────────
  Logo bg teal  : #0a8c7a  (primary teal — trust, growth, healing)
  Logo gold     : #c9a84c  (gold accent — warmth, optimism, value)
  Deep teal     : #065a4e  (dark sections — depth, grounding)
  Mid teal      : #0d7a6a  (hover states)
  Pale teal bg  : #f0faf8  (light sections — fresh, open)
  Soft teal     : #e0f4f1  (subtle tints)
  Muted gold    : #e8c97a  (light gold tints)
  Off-white     : #faf9f6  (warm neutral background)
  Dark          : #042d26  (headings, deep text)
  Body text     : #2a4a44  (readable dark teal-grey)
*/

interface NavLinkItem { label: string; href: string; }

const Navbar: React.FC = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [mobileOpen, setMobileOpen] = useState(false);
  const LOGO = "data:image/jpeg;base64,";

  const links: NavLinkItem[] = [
    { label: 'Home',     href: '#home'     },
    { label: 'Features', href: '#features' },
    { label: 'About',    href: '#about'    },
  ];

  useEffect(() => {
    const h = () => setIsScrolled(window.scrollY > 10);
    window.addEventListener('scroll', h);
    return () => window.removeEventListener('scroll', h);
  }, []);

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,500;1,300;1,400&family=Playfair+Display:ital,wght@0,400;0,500;0,700;1,400&family=Jost:wght@300;400;500&display=swap');

        .nav-r {
          position:fixed; top:0; left:0; right:0; z-index:100; transition:all .45s ease;
        }
        .nav-r.scrolled {
          background:rgba(250,249,246,0.97); backdrop-filter:blur(20px);
          border-bottom:1px solid rgba(10,140,122,0.15);
          box-shadow:0 4px 40px rgba(6,90,78,0.08);
        }
        .nav-inner {
          max-width:1280px; margin:0 auto; padding:0 2.5rem;
          height:72px; display:flex; align-items:center; justify-content:space-between;
        }

        /* Brand */
        .nav-brand { display:flex; align-items:center; gap:.75rem; text-decoration:none; }
        .nav-logo-ring {
          width:44px; height:44px; border-radius:50%; overflow:hidden;
          border:2px solid rgba(201,168,76,0.4); flex-shrink:0;
          box-shadow:0 2px 16px rgba(201,168,76,0.2);
        }
        .nav-logo-ring img { width:100%; height:100%; object-fit:cover; object-position:center 30%; }
        .nav-brand-text {}
        .nav-brand-name {
          font-family:'Playfair Display',serif; font-size:1.35rem; font-weight:500;
          color:#042d26; letter-spacing:.04em; display:block; line-height:1;
        }
        .nav-brand-sub {
          font-family:'Jost',sans-serif; font-size:.55rem; font-weight:300;
          letter-spacing:.28em; text-transform:uppercase; color:#0a8c7a;
          display:block; margin-top:2px;
        }

        /* Desktop links */
        .nav-desktop { display:flex; align-items:center; gap:2.5rem; }
        .nav-link {
          font-family:'Jost',sans-serif; font-size:.71rem; font-weight:400;
          letter-spacing:.2em; text-transform:uppercase; color:#2a4a44;
          text-decoration:none; position:relative; padding-bottom:2px; transition:color .3s;
        }
        .nav-link::after {
          content:''; position:absolute; bottom:0; left:0;
          width:0; height:1px; background:#c9a84c; transition:width .3s;
        }
        .nav-link:hover { color:#042d26; }
        .nav-link:hover::after { width:100%; }

        .nav-cta {
          font-family:'Jost',sans-serif; font-size:.68rem; font-weight:500;
          letter-spacing:.18em; text-transform:uppercase;
          color:#042d26; background:linear-gradient(135deg,#c9a84c,#e8c97a);
          text-decoration:none; padding:.62rem 1.5rem;
          border:1px solid #c9a84c; transition:all .3s;
          box-shadow:0 2px 12px rgba(201,168,76,0.25);
        }
        .nav-cta:hover {
          background:linear-gradient(135deg,#b8943a,#c9a84c);
          box-shadow:0 4px 20px rgba(201,168,76,0.35);
        }
        .nav-div { width:1px; height:20px; background:rgba(10,140,122,0.2); }

        /* Mobile */
        .nav-toggle {
          display:none; background:none; border:none; cursor:pointer; color:#042d26; padding:4px;
        }
        .nav-mob {
          position:fixed; top:72px; left:0; right:0; background:#faf9f6;
          border-bottom:1px solid rgba(10,140,122,0.15);
          padding:1.5rem 2rem 2rem; display:flex; flex-direction:column; gap:.5rem;
          box-shadow:0 20px 60px rgba(6,90,78,0.12);
        }
        .nav-mob-link {
          font-family:'Jost',sans-serif; font-size:.78rem; font-weight:400;
          letter-spacing:.2em; text-transform:uppercase; color:#2a4a44;
          text-decoration:none; padding:.75rem 0;
          border-bottom:1px solid rgba(10,140,122,0.1);
        }
        .nav-mob-cta {
          font-family:'Jost',sans-serif; font-size:.68rem; font-weight:500;
          letter-spacing:.18em; text-transform:uppercase;
          color:#042d26; background:linear-gradient(135deg,#c9a84c,#e8c97a);
          text-decoration:none; padding:.8rem 1.5rem; text-align:center; margin-top:.75rem;
        }
        @media (max-width:768px) {
          .nav-desktop { display:none; }
          .nav-toggle   { display:block; }
        }
      `}</style>

      <nav className={`nav-r ${isScrolled ? 'scrolled' : ''}`}>
        <div className="nav-inner">
          <Link href="/" className="nav-brand">
            <div className="nav-logo-ring">
              <img src={LOGO} alt="Sentira" />
            </div>
            <div className="nav-brand-text">
              <span className="nav-brand-name">Sentira</span>
              {/* <span className="nav-brand-sub">Emotional Wellness</span> */}
            </div>
          </Link>

          <div className="nav-desktop">
            {links.map(l => <Link key={l.href} href={l.href} className="nav-link">{l.label}</Link>)}
            <div className="nav-div" />
            <Link href="/login" className="nav-cta">Begin</Link>
          </div>

          <button className="nav-toggle" onClick={() => setMobileOpen(!mobileOpen)}>
            {mobileOpen ? <X size={22}/> : <Menu size={22}/>}
          </button>
        </div>

        {mobileOpen && (
          <div className="nav-mob">
            {links.map(l => (
              <Link key={l.href} href={l.href} className="nav-mob-link"
                onClick={() => setMobileOpen(false)}>{l.label}</Link>
            ))}
            <Link href="/login" className="nav-mob-cta">Login / Register</Link>
          </div>
        )}
      </nav>
    </>
  );
};

export default Navbar;
